import{E as e,R as t,_ as n,h as r,pt as i,x as a,z as o}from"./runtime-core.esm-bundler-zlLwmkyI.js";var s={class:`ant-doc vp-doc`},c=a({__name:`secondary-development.zh-CN`,setup(a,{expose:c}){let l={title:`二次开发`,frontmatter:{title:`二次开发`},headers:[{level:2,title:`模板仓库`,slug:`模板仓库`,link:`#模板仓库`,children:[]},{level:2,title:`适合什么场景`,slug:`适合什么场景`,link:`#适合什么场景`,children:[]},{level:2,title:`模板内置能力`,slug:`模板内置能力`,link:`#模板内置能力`,children:[]},{level:2,title:`开始之前先做一件事`,slug:`开始之前先做一件事`,link:`#开始之前先做一件事`,children:[]},{level:2,title:`快速开始`,slug:`快速开始`,link:`#快速开始`,children:[{level:3,title:`1. 克隆模板`,slug:`_1-克隆模板`,link:`#_1-克隆模板`,children:[]},{level:3,title:`2. 安装依赖`,slug:`_2-安装依赖`,link:`#_2-安装依赖`,children:[]},{level:3,title:`3. 启动文档站`,slug:`_3-启动文档站`,link:`#_3-启动文档站`,children:[]},{level:3,title:`4. 构建组件库`,slug:`_4-构建组件库`,link:`#_4-构建组件库`,children:[]}]},{level:2,title:`推荐开发方式`,slug:`推荐开发方式`,link:`#推荐开发方式`,children:[{level:3,title:`1. 先改包名和发布信息`,slug:`_1-先改包名和发布信息`,link:`#_1-先改包名和发布信息`,children:[]},{level:3,title:`2. 开发你的业务组件`,slug:`_2-开发你的业务组件`,link:`#_2-开发你的业务组件`,children:[]},{level:3,title:`3. 编写文档页面`,slug:`_3-编写文档页面`,link:`#_3-编写文档页面`,children:[]},{level:3,title:`4. 为文档补充 Demo`,slug:`_4-为文档补充-demo`,link:`#_4-为文档补充-demo`,children:[]}]},{level:2,title:`目录结构`,slug:`目录结构`,link:`#目录结构`,children:[]},{level:2,title:`主题说明`,slug:`主题说明`,link:`#主题说明`,children:[]},{level:2,title:`适合怎样的团队`,slug:`适合怎样的团队`,link:`#适合怎样的团队`,children:[]}],description:``},u={title:`二次开发`},d=i({});o(`__pageData__`,e=>{d.value=e});let f=e(`__pageData__`,null);return f&&f(l),o(`__pageInfo__`,l),c({frontmatter:u,pageData:l}),(e,i)=>(t(),r(`div`,s,[...i[0]||=[n(`<p>如果你希望基于 <code>antdv-next</code> 搭建自己的业务组件库、文档站和 Demo 系统，我们已经提供了一套可直接开始二次开发的模板仓库：<a href="https://github.com/antdv-next/docs-base">docs-base</a>。</p><p>这个模板不是简单的脚手架示例，而是一套围绕组件库开发场景整理好的基础工程。它把组件源码、文档页面、Markdown Demo 渲染链路和打包发布能力放在同一个项目里，适合团队持续沉淀业务组件并对外发布。</p><h2 id="模板仓库" tabindex="-1">模板仓库 <a class="header-anchor" href="#模板仓库" aria-label="Permalink to &quot;模板仓库&quot;">​</a></h2><ul><li>GitHub: <a href="https://github.com/antdv-next/docs-base">https://github.com/antdv-next/docs-base</a></li><li>中文 README: <a href="https://github.com/antdv-next/docs-base/blob/main/README.zh-CN.md">README.zh-CN.md</a></li></ul><h2 id="适合什么场景" tabindex="-1">适合什么场景 <a class="header-anchor" href="#适合什么场景" aria-label="Permalink to &quot;适合什么场景&quot;">​</a></h2><p>当你希望：</p><ul><li>基于 <code>antdv-next</code> 扩展自己的业务组件库</li><li>将组件源码、示例和文档统一维护</li><li>输出带类型声明的 Vue 3 组件包</li><li>用 Markdown 写文档，同时直接嵌入真实 Vue Demo</li><li>同时维护中英文文档页面</li><li>自定义自己的主题体系，而不是继承一套固定视觉方案</li></ul><p>那么可以直接从这个模板开始。</p><h2 id="模板内置能力" tabindex="-1">模板内置能力 <a class="header-anchor" href="#模板内置能力" aria-label="Permalink to &quot;模板内置能力&quot;">​</a></h2><ul><li>Vue 3 + TypeScript + Vite</li><li>以 <code>antdv-next</code> 作为基础 UI 组件依赖</li><li>支持保留模块结构、Bundled ESM、UMD 三种构建产物</li><li>自动生成组件类型声明</li><li>自定义 Markdown 转 Vue 的文档渲染链路</li><li>Demo 代码展示、源码提取与热更新</li><li>集成 UnoCSS、Vue Router、Pinia、Vue I18n</li><li>内置可直接扩展的示例组件和文档页面</li></ul><h2 id="开始之前先做一件事" tabindex="-1">开始之前先做一件事 <a class="header-anchor" href="#开始之前先做一件事" aria-label="Permalink to &quot;开始之前先做一件事&quot;">​</a></h2><p>模板默认使用 <code>@org/components</code> 作为占位包名。开始二次开发前，建议先全局搜索并替换 <code>@org/components</code>，统一改成你自己的真实包名，再继续后续开发。</p><h2 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h2><h3 id="_1-克隆模板" tabindex="-1">1. 克隆模板 <a class="header-anchor" href="#_1-克隆模板" aria-label="Permalink to &quot;1. 克隆模板&quot;">​</a></h3><div class="language-bash ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">git</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> clone</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> https://github.com/antdv-next/docs-base.git</span></span>
<span class="line"><span style="--ant-doc-light:#998418;--ant-doc-dark:#B8A965;">cd</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> docs-base</span></span></code></pre></div><h3 id="_2-安装依赖" tabindex="-1">2. 安装依赖 <a class="header-anchor" href="#_2-安装依赖" aria-label="Permalink to &quot;2. 安装依赖&quot;">​</a></h3><div class="language-bash ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">pnpm</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> install</span></span></code></pre></div><h3 id="_3-启动文档站" tabindex="-1">3. 启动文档站 <a class="header-anchor" href="#_3-启动文档站" aria-label="Permalink to &quot;3. 启动文档站&quot;">​</a></h3><div class="language-bash ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">pnpm</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> docs:dev</span></span></code></pre></div><p>本地开发地址默认是 <a href="http://localhost:6878">http://localhost:6878</a>。</p><h3 id="_4-构建组件库" tabindex="-1">4. 构建组件库 <a class="header-anchor" href="#_4-构建组件库" aria-label="Permalink to &quot;4. 构建组件库&quot;">​</a></h3><div class="language-bash ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">pnpm</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> build</span></span></code></pre></div><p>其他常用命令：</p><div class="language-bash ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">pnpm</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> docs:build</span></span>
<span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">pnpm</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> docs:preview</span></span>
<span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">pnpm</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> type-check</span></span>
<span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">pnpm</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> test:unit</span></span></code></pre></div><h2 id="推荐开发方式" tabindex="-1">推荐开发方式 <a class="header-anchor" href="#推荐开发方式" aria-label="Permalink to &quot;推荐开发方式&quot;">​</a></h2><h3 id="_1-先改包名和发布信息" tabindex="-1">1. 先改包名和发布信息 <a class="header-anchor" href="#_1-先改包名和发布信息" aria-label="Permalink to &quot;1. 先改包名和发布信息&quot;">​</a></h3><ul><li>全局替换 <code>@org/components</code></li><li>更新 <code>package.json</code> 中的包名与发布信息</li></ul><h3 id="_2-开发你的业务组件" tabindex="-1">2. 开发你的业务组件 <a class="header-anchor" href="#_2-开发你的业务组件" aria-label="Permalink to &quot;2. 开发你的业务组件&quot;">​</a></h3><p>在 <code>components/</code> 下新增或改造组件，并在 <code>components/index.ts</code> 中统一导出，保持对外 API 清晰稳定。</p><h3 id="_3-编写文档页面" tabindex="-1">3. 编写文档页面 <a class="header-anchor" href="#_3-编写文档页面" aria-label="Permalink to &quot;3. 编写文档页面&quot;">​</a></h3><p>在 <code>docs/src/pages/</code> 下新增 Markdown 文档。当前模板通过 <code>import.meta.glob</code> 自动把 <code>.md</code> 页面注册成路由。</p><p>推荐沿用以下多语言命名方式：</p><ul><li><code>*.zh-CN.md</code></li><li><code>*.en-US.md</code></li></ul><h3 id="_4-为文档补充-demo" tabindex="-1">4. 为文档补充 Demo <a class="header-anchor" href="#_4-为文档补充-demo" aria-label="Permalink to &quot;4. 为文档补充 Demo&quot;">​</a></h3><p>在文档页面同级的 <code>demo/</code> 目录中放置示例文件，然后在 Markdown 中这样引用：</p><div class="language-md ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang">md</span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span style="--ant-doc-light:#393A34;--ant-doc-dark:#DBD7CAEE;">&lt;demo-group&gt;</span></span>
<span class="line"><span style="--ant-doc-light:#393A34;--ant-doc-dark:#DBD7CAEE;">  &lt;demo src=&quot;./demo/basic.vue&quot;&gt;基础示例&lt;/demo&gt;</span></span>
<span class="line"><span style="--ant-doc-light:#393A34;--ant-doc-dark:#DBD7CAEE;">&lt;/demo-group&gt;</span></span></code></pre></div><p>这样文档系统会自动完成：</p><ul><li>渲染实时 Vue 示例</li><li>提取源码内容</li><li>生成高亮代码块</li><li>开发时热更新 Demo 元数据</li></ul><h2 id="目录结构" tabindex="-1">目录结构 <a class="header-anchor" href="#目录结构" aria-label="Permalink to &quot;目录结构&quot;">​</a></h2><div class="language-text ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span>.</span></span>
<span class="line"><span>├─ components/                 # 业务组件源码目录</span></span>
<span class="line"><span>├─ docs/                       # 文档站应用</span></span>
<span class="line"><span>│  ├─ src/pages/               # Markdown 页面与首页</span></span>
<span class="line"><span>│  ├─ src/components/demo/     # Demo 渲染与源码展示</span></span>
<span class="line"><span>│  └─ plugins/markdown/        # Markdown / Demo 转换插件</span></span>
<span class="line"><span>├─ vite.build.config.ts        # 保留模块结构的组件构建</span></span>
<span class="line"><span>├─ vite.esm.config.ts          # ESM 打包构建</span></span>
<span class="line"><span>├─ vite.umd.config.ts          # UMD 打包构建</span></span>
<span class="line"><span>└─ global.d.ts                 # 全局组件类型声明</span></span></code></pre></div><h2 id="主题说明" tabindex="-1">主题说明 <a class="header-anchor" href="#主题说明" aria-label="Permalink to &quot;主题说明&quot;">​</a></h2><p>这个模板本身不预设业务主题。你可以基于自己的品牌规范去实现颜色体系、设计 Token 和组件视觉风格。主题能力可以结合 <a href="/docs/vue/customize-theme">定制主题</a> 一起使用。</p><h2 id="适合怎样的团队" tabindex="-1">适合怎样的团队 <a class="header-anchor" href="#适合怎样的团队" aria-label="Permalink to &quot;适合怎样的团队&quot;">​</a></h2><p>如果你的目标不是单独维护一个 Demo 仓库，而是希望把：</p><ul><li>组件实现</li><li>文档说明</li><li>在线示例</li><li>多语言页面</li><li>构建产物</li></ul><p>统一放在一个仓库中管理，那么 <code>docs-base</code> 会比从零搭建更省时间。</p>`,46)]]))}});export{c as default};